def _capture_loky_diagnostics(label: str) -> dict[str, Any]:
    """Best-effort loky/joblib semaphore diagnostics for smoke debugging."""
    import glob

    diag: dict[str, Any] = {
        "label": str(label or "").strip(),
        "pid": os.getpid(),
        "modules_present": {
            "loky": "loky" in sys.modules,
            "joblib": "joblib" in sys.modules,
        },
        "threads": [],
        "executors": [],
        "semaphores": [],
        "env": {
            "LOKY_START_METHOD": os.environ.get("LOKY_START_METHOD"),
            "LOKY_MAX_CPU_COUNT": os.environ.get("LOKY_MAX_CPU_COUNT"),
            "JOBLIB_START_METHOD": os.environ.get("JOBLIB_START_METHOD"),
            "STUDYPLAN_SMOKE_MODE": os.environ.get("STUDYPLAN_SMOKE_MODE"),
        },
    }
    try:
        for t in threading.enumerate():
            name = str(getattr(t, "name", "") or "")
            if ("loky" in name.lower()) or ("executor" in name.lower()):
                diag["threads"].append(
                    {
                        "name": name,
                        "ident": getattr(t, "ident", None),
                        "daemon": bool(getattr(t, "daemon", False)),
                        "alive": bool(t.is_alive()),
                    }
                )
    except Exception:
        pass
    try:
        import importlib

        reusable_mod = None
        for mod_name in ("joblib.externals.loky.reusable_executor", "loky.reusable_executor"):
            try:
                reusable_mod = importlib.import_module(mod_name)
            except Exception:
                continue
            break
        if reusable_mod is not None:
            ex = getattr(reusable_mod, "_executor", None)
            if ex is not None:
                pending = getattr(ex, "_pending_work_items", {}) or {}
                try:
                    pending_count = len(pending)
                except Exception:
                    pending_count = None
                diag["executors"].append(
                    {
                        "type": type(ex).__name__,
                        "id": id(ex),
                        "max_workers": getattr(ex, "_max_workers", None),
                        "pending": pending_count,
                    }
                )
        backend_rt_mod = None
        for mod_name in ("joblib.externals.loky.backend.resource_tracker", "loky.backend.resource_tracker"):
            try:
                backend_rt_mod = importlib.import_module(mod_name)
            except Exception:
                continue
            break
        if backend_rt_mod is not None:
            rt = getattr(backend_rt_mod, "_resource_tracker", None)
            if rt is not None:
                diag["loky_resource_tracker"] = {
                    "pid": getattr(rt, "_pid", None),
                    "fd": getattr(rt, "_fd", None),
                }
    except Exception as exc:
        diag["executors"] = [{"error": str(exc)}]
    try:
        diag["semaphores"] = glob.glob("/dev/shm/sem.loky*") + glob.glob("/dev/shm/sem.*loky*")
    except Exception:
        pass
    return diag


def _log_loky_diagnostics(label: str) -> None:
    try:
        print(
            f"LOKY_DIAG[{label}] {json.dumps(_capture_loky_diagnostics(label), ensure_ascii=True, default=str)}",
            flush=True,
        )
    except Exception:
        pass

# Suppress known noisy GTK/GLib warnings without hiding real errors.
def _install_log_filters() -> None:
    noisy_substrings = (
        "Unknown key gtk-toolbar-style",
        "Unknown key gtk-toolbar-icon-size",
        "Unknown key gtk-button-images",
        "Unknown key gtk-menu-images",
        "Unknown key gtk-modules",
        "Warning: You are sending unauthenticated requests to the HF Hub.",
        "g_main_context_pop_thread_default: assertion 'stack != NULL' failed",
    )

    class _FilteredStderr:
        def __init__(self, stream):
            self._stream = stream
            self._buffer = ""

        def write(self, data):
            if not isinstance(data, str):
                try:
                    data = data.decode("utf-8", "ignore")
                except Exception:
                    data = str(data)
            self._buffer += data
            while "\n" in self._buffer:
                line, self._buffer = self._buffer.split("\n", 1)
                if any(needle in line for needle in noisy_substrings):
                    continue
                self._stream.write(line + "\n")

        def flush(self):
            if self._buffer:
                line = self._buffer
                self._buffer = ""
                if not any(needle in line for needle in noisy_substrings):
                    self._stream.write(line)
            try:
                self._stream.flush()
            except Exception:
                pass

        def isatty(self):
            return getattr(self._stream, "isatty", lambda: False)()

        def fileno(self):
            return getattr(self._stream, "fileno", lambda: -1)()

        @property
        def encoding(self):
            return getattr(self._stream, "encoding", "utf-8")

    def _handler(domain, level, message, _user_data):
        msg = message or ""
        for needle in noisy_substrings:
            if needle in msg:
                return
        try:
            sys.stderr.write(f"{domain}: {msg}\n" if domain else f"{msg}\n")
        except Exception:
            pass

    def _writer(log_level, fields, n_fields, _user_data):
        msg = ""
        try:
            if isinstance(fields, dict):
                msg = str(fields.get("MESSAGE", "") or "")
            else:
                for idx in range(int(n_fields or 0)):
                    field = fields[idx]
                    if getattr(field, "key", "") == "MESSAGE":
                        try:
                            msg = field.value.decode("utf-8", "ignore")
                        except Exception:
                            msg = str(field.value)
                        break
        except Exception:
            msg = ""
        for needle in noisy_substrings:
            if needle in msg:
                return GLib.LogWriterOutput.HANDLED
        return GLib.LogWriterOutput.UNHANDLED

    try:
        if hasattr(GLib, "log_set_writer_func"):
            GLib.log_set_writer_func(_writer, None)
        else:
            GLib.log_set_default_handler(_handler, None)
    except Exception:
        pass

    try:
        if not isinstance(sys.stderr, _FilteredStderr):
            sys.stderr = _FilteredStderr(sys.stderr)
    except Exception:
        pass

_install_log_filters()

