def configure_font_rendering() -> None:
    settings = Gtk.Settings.get_default()
    if not settings:
        return
    # Light hinting + antialiasing improves legibility on smaller displays.
    if hasattr(settings.props, "gtk_xft_antialias"):
        settings.props.gtk_xft_antialias = 1
    if hasattr(settings.props, "gtk_xft_hinting"):
        settings.props.gtk_xft_hinting = 1
    if hasattr(settings.props, "gtk_xft_hintstyle"):
        settings.props.gtk_xft_hintstyle = "hintslight"


class TutorWorkspaceState(dict[str, Any]):
    """Structured tutor workspace runtime state with centralized defaults."""

    def __init__(
        self,
        *,
        tutor_help_feedback: str = "",
        tutor_help_feedback_at: str = "",
        practice_session_id: str = "tutor-workspace",
    ) -> None:
        super().__init__()
        self.update(
            {
                "active": False,
                "job_id": 0,
                "cancel_event": None,
                "model": "",
                "draft_user": "",
                "draft_assistant": "",
                "stream_render_pending": False,
                "stream_render_force": False,
                "stream_last_clean_text": "",
                "stream_label_inserted": False,
                "stream_last_chunk_at": 0.0,
                "stream_last_render_at": 0.0,
                "stream_watchdog_last_force_at": 0.0,
                "stream_watchdog_forced_flushes": 0,
                "stream_watchdog_id": 0,
                "model_poll_id": 0,
                "models": [],
                "model_poll_errors": 0,
                "follow_live": True,
                "follow_manual_override": False,
                "ignore_scroll_event": False,
                "refresh_runtime": None,
                "refresh_status": None,
                "refresh_practice": None,
                "refresh_layout": None,
                "set_running": None,
                "gap_generation_active": False,
                "practice_session_id": str(practice_session_id or "tutor-workspace"),
                "tutor_trust_summary": "",
                "tutor_trust_details": "",
                "tutor_help_feedback": str(tutor_help_feedback or ""),
                "tutor_help_feedback_at": str(tutor_help_feedback_at or ""),
                "tutor_help_feedback_turn": 0,
                "tutor_help_followup_prompt": "",
            }
        )
        self.clear_practice_plan()

    def reset_stream_runtime(self, *, clear_drafts: bool = False) -> None:
        self["stream_render_pending"] = False
        self["stream_render_force"] = False
        self["stream_last_clean_text"] = ""
        self["stream_label_inserted"] = False
        self["stream_last_chunk_at"] = 0.0
        self["stream_last_render_at"] = 0.0
        self["stream_watchdog_last_force_at"] = 0.0
        self["stream_watchdog_forced_flushes"] = 0
        if clear_drafts:
            self["draft_user"] = ""
            self["draft_assistant"] = ""

    def clear_practice_plan(self) -> None:
        self["practice_plan_result"] = None
        self["practice_session_state"] = None
        self["practice_learner_profile"] = None
        self["practice_item"] = None
        self["practice_action_plan"] = None
        self["practice_action_status"] = ""
        self.reset_practice_attempt_state()

    def reset_practice_attempt_state(self) -> None:
        self["practice_result"] = None
        self["practice_variant_candidate"] = None
        self["practice_intervention_policy"] = None
        self["practice_hint_policy_state"] = {}
        self["practice_hint_policy_last_decision"] = None
        self["practice_hint_policy_tick_id"] = 0
        self["practice_hint_policy_cooldown_active"] = False
        self["practice_hint_use_count"] = 0
        self["practice_transfer_base"] = None
        self["practice_last_transfer_summary"] = None
        self["practice_next_guidance"] = None
        self["practice_session_quality_summary"] = {}

    def set_practice_plan(
        self,
        *,
        plan_result: Any,
        session_state: Any,
        learner_profile: Any,
        practice_item: Any,
        action_plan: Any,
    ) -> None:
        self["practice_plan_result"] = plan_result
        self["practice_session_state"] = session_state
        self["practice_learner_profile"] = learner_profile
        self["practice_item"] = practice_item
        self["practice_action_plan"] = action_plan
        self["practice_action_status"] = ""
        self.reset_practice_attempt_state()

    def activate_variant(self, variant_item: Any) -> None:
        self["practice_item"] = variant_item
        self.reset_practice_attempt_state()

    def practice_session_id(self) -> str:
        return str(self.get("practice_session_id", "tutor-workspace") or "tutor-workspace")

    def practice_session_state(self) -> TutorSessionState | None:
        candidate = self.get("practice_session_state")
        return candidate if isinstance(candidate, TutorSessionState) else None

    def set_practice_session_state(self, session_state: Any) -> None:
        self["practice_session_state"] = session_state if isinstance(session_state, TutorSessionState) else None

    def practice_learner_profile(self) -> TutorLearnerProfileSnapshot | None:
        candidate = self.get("practice_learner_profile")
        return candidate if isinstance(candidate, TutorLearnerProfileSnapshot) else None

    def set_practice_learner_profile(self, learner_profile: Any) -> None:
        self["practice_learner_profile"] = (
            learner_profile if isinstance(learner_profile, TutorLearnerProfileSnapshot) else None
        )

    def practice_item(self) -> TutorPracticeItem | None:
        candidate = self.get("practice_item")
        return candidate if isinstance(candidate, TutorPracticeItem) else None

    def set_practice_item(self, practice_item: Any) -> None:
        self["practice_item"] = practice_item if isinstance(practice_item, TutorPracticeItem) else None

    def practice_result(self) -> TutorAssessmentResult | None:
        candidate = self.get("practice_result")
        return candidate if isinstance(candidate, TutorAssessmentResult) else None

    def record_practice_result(self, result: Any) -> TutorAssessmentResult | None:
        self["practice_result"] = result if isinstance(result, TutorAssessmentResult) else None
        self["practice_variant_candidate"] = None
        self["practice_intervention_policy"] = None
        self["practice_hint_policy_last_decision"] = None
        return self.practice_result()

    def practice_variant_candidate(self) -> TutorPracticeItem | None:
        candidate = self.get("practice_variant_candidate")
        return candidate if isinstance(candidate, TutorPracticeItem) else None

    def set_practice_variant_candidate(self, variant_item: Any) -> None:
        self["practice_variant_candidate"] = variant_item if isinstance(variant_item, TutorPracticeItem) else None

    def practice_intervention_policy(self) -> dict[str, Any] | None:
        candidate = self.get("practice_intervention_policy")
        return dict(candidate) if isinstance(candidate, dict) else None

    def set_practice_intervention_policy(self, policy: Any) -> None:
        self["practice_intervention_policy"] = dict(policy) if isinstance(policy, dict) else None

    def practice_next_guidance(self) -> dict[str, Any] | None:
        candidate = self.get("practice_next_guidance")
        return dict(candidate) if isinstance(candidate, dict) else None

    def set_practice_next_guidance(self, guidance: Any) -> None:
        self["practice_next_guidance"] = dict(guidance) if isinstance(guidance, dict) else None

    def practice_session_quality_summary(self) -> dict[str, Any]:
        candidate = self.get("practice_session_quality_summary")
        return dict(candidate) if isinstance(candidate, dict) else {}

    def set_practice_session_quality_summary(self, summary: Any) -> None:
        self["practice_session_quality_summary"] = dict(summary) if isinstance(summary, dict) else {}

    def tutor_help_feedback(self) -> str:
        return str(self.get("tutor_help_feedback", "") or "").strip()

    def set_tutor_help_feedback(self, signal: Any, *, turn: int | None = None, at: str | None = None) -> None:
        self["tutor_help_feedback"] = str(signal or "").strip()
        if at is not None:
            self["tutor_help_feedback_at"] = str(at or "").strip()
        if turn is not None:
            try:
                self["tutor_help_feedback_turn"] = max(0, int(turn))
            except Exception:
                self["tutor_help_feedback_turn"] = 0

    def tutor_help_feedback_at(self) -> str:
        return str(self.get("tutor_help_feedback_at", "") or "").strip()

    def tutor_help_feedback_turn(self) -> int:
        try:
            return max(0, int(self.get("tutor_help_feedback_turn", 0) or 0))
        except Exception:
            return 0

    def tutor_trust_summary(self) -> str:
        return str(self.get("tutor_trust_summary", "") or "").strip()

    def tutor_trust_details(self) -> str:
        return str(self.get("tutor_trust_details", "") or "").strip()

    def clear_tutor_trust(self) -> None:
        self["tutor_trust_summary"] = ""
        self["tutor_trust_details"] = ""

    def set_tutor_trust(self, *, summary: Any = "", details: Any = "") -> None:
        self["tutor_trust_summary"] = str(summary or "").strip()
        self["tutor_trust_details"] = str(details or "").strip()


class AppDialog(Gtk.Window):
    def __init__(self, title: str | None = None, transient_for=None, modal: bool = False):
        app = None
        try:
            if transient_for is not None:
                app = transient_for.get_application()
        except Exception:
            app = None
        if app is not None:
            super().__init__(application=app, transient_for=transient_for)
        else:
            super().__init__(transient_for=transient_for)
        if title:
            self.set_title(title)
        self.set_modal(bool(modal))
        try:
            self.add_css_class("app-dialog-window")
        except Exception:
            pass
        try:
            self.set_destroy_with_parent(True)
        except Exception:
            pass
        self._response_handlers: list[tuple] = []
        self._default_response = None

        main = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=8)
        self._content_area = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=8)
        self._content_area.set_margin_top(12)
        self._content_area.set_margin_bottom(12)
        self._content_area.set_margin_start(12)
        self._content_area.set_margin_end(12)
        self._action_area = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=8)
        self._action_area.set_halign(Gtk.Align.END)
        main.append(self._content_area)
        main.append(self._action_area)
        self.set_child(main)

    def get_content_area(self):
        return self._content_area

    def add_button(self, label, response_id):
        if isinstance(label, str) and "_" in label:
            btn = Gtk.Button.new_with_mnemonic(label)
        else:
            btn = Gtk.Button(label=label)
        try:
            btn.add_css_class("dialog-action")
        except Exception:
            pass
        btn.connect("clicked", lambda _b, resp=response_id: self.response(resp))
        self._action_area.append(btn)
        if self._default_response == response_id:
            try:
                self.set_default_widget(btn)
            except Exception:
                pass
        return btn

    def add_buttons(self, *args):
        for i in range(0, len(args), 2):
            if i + 1 >= len(args):
                break
            self.add_button(args[i], args[i + 1])

    def set_default_response(self, response_id):
        self._default_response = response_id

    def response(self, response_id):
        for handler, user_data in list(self._response_handlers):
            try:
                if user_data:
                    handler(self, response_id, *user_data)
                else:
                    handler(self, response_id)
            except Exception:
                pass

    def connect(self, detailed_signal, handler, *user_data):
        if detailed_signal == "response":
            self._response_handlers.append((handler, user_data))
            return len(self._response_handlers)
        return super().connect(detailed_signal, handler, *user_data)


class AppMessageDialog:
    def __init__(
        self,
        text: str | None = None,
        transient_for=None,
        modal: bool = True,
        message_type=None,
        buttons=None,
        secondary_text: str | None = None,
        force_fallback: bool = False,
    ):
        self._parent = transient_for
        self._message = text or ""
        self._detail = secondary_text or ""
        self._buttons: list[tuple[str, int]] = []
        self._response_handlers: list[tuple] = []
        self._default_response = None
        self._cancel_response = None
        self._modal = bool(modal)
        self._use_alert = (not force_fallback) and hasattr(Gtk, "AlertDialog")
        self._dialog = None

        if not self._use_alert:
            # Fallback to custom window if AlertDialog is unavailable.
            self._dialog = AppDialog(transient_for=transient_for, modal=modal)
            content = self._dialog.get_content_area()
            label = Gtk.Label(label=self._message)
            label.set_wrap(True)
            label.set_halign(Gtk.Align.START)
            content.append(label)
            if self._detail:
                detail = Gtk.Label(label=self._detail)
                detail.set_wrap(True)
                detail.set_halign(Gtk.Align.START)
                detail.add_css_class("muted")
                content.append(detail)

        # Preload buttons if provided.
        if buttons is None:
            buttons = Gtk.ButtonsType.OK
        self._apply_buttons_type(buttons)

    def _apply_buttons_type(self, buttons) -> None:
        mapping = {
            Gtk.ButtonsType.NONE: [],
            Gtk.ButtonsType.OK: [("OK", Gtk.ResponseType.OK)],
            Gtk.ButtonsType.CLOSE: [("Close", Gtk.ResponseType.CLOSE)],
            Gtk.ButtonsType.CANCEL: [("Cancel", Gtk.ResponseType.CANCEL)],
            Gtk.ButtonsType.YES_NO: [("No", Gtk.ResponseType.NO), ("Yes", Gtk.ResponseType.YES)],
            Gtk.ButtonsType.OK_CANCEL: [("Cancel", Gtk.ResponseType.CANCEL), ("OK", Gtk.ResponseType.OK)],
        }
        for label, resp in mapping.get(buttons, []):
            self.add_button(label, resp)

    def add_button(self, label, response_id):
        self._buttons.append((label, response_id))
        if self._dialog is not None:
            self._dialog.add_button(label, response_id)
        return None

    def add_buttons(self, *args):
        for i in range(0, len(args), 2):
            if i + 1 >= len(args):
                break
            self.add_button(args[i], args[i + 1])

    def set_default_response(self, response_id):
        self._default_response = response_id

    def set_cancel_response(self, response_id):
        self._cancel_response = response_id

    def set_title(self, title: str) -> None:
        # GTK4 AlertDialog has no title; use heading when available.
        if self._dialog is not None:
            try:
                self._dialog.set_title(title)
            except Exception:
                pass
            return
        self._heading = title

    def connect(self, detailed_signal, handler, *user_data):
        if detailed_signal == "response":
            self._response_handlers.append((handler, user_data))
            if self._dialog is not None:
                self._dialog.connect("response", handler, *user_data)
            return len(self._response_handlers)
        if self._dialog is not None:
            return self._dialog.connect(detailed_signal, handler, *user_data)
        return 0

    def _emit_response(self, response_id):
        for handler, user_data in list(self._response_handlers):
            try:
                if user_data:
                    handler(self, response_id, *user_data)
                else:
                    handler(self, response_id)
            except Exception:
                pass

    def present(self):
        if self._dialog is not None:
            self._dialog.present()
            return
        dialog = Gtk.AlertDialog()
        try:
            dialog.set_message(self._message)
        except Exception:
            pass
        try:
            heading = getattr(self, "_heading", None)
            if heading:
                dialog.set_heading(heading)
        except Exception:
            pass
        if self._detail:
            try:
                dialog.set_detail(self._detail)
            except Exception:
                pass
        if not self._buttons:
            self._buttons = [("OK", Gtk.ResponseType.OK)]
        labels = [label for label, _ in self._buttons]
        try:
            dialog.set_buttons(labels)
        except Exception:
            pass
        if self._default_response is not None:
            try:
                idx = [resp for _, resp in self._buttons].index(self._default_response)
                dialog.set_default_button(idx)
            except Exception:
                pass
        if self._cancel_response is not None:
            try:
                idx = [resp for _, resp in self._buttons].index(self._cancel_response)
                dialog.set_cancel_button(idx)
            except Exception:
                pass

        def _on_choose(_dialog, res):
            idx = -1
            try:
                idx = _dialog.choose_finish(res)
            except Exception:
                idx = -1
            if 0 <= idx < len(self._buttons):
                response_id = self._buttons[idx][1]
            else:
                response_id = Gtk.ResponseType.CANCEL
            self._emit_response(response_id)

        try:
            dialog.choose(self._parent, None, _on_choose)
        except Exception:
            # Fallback to non-blocking show if choose isn't available.
            try:
                dialog.show(self._parent)
            except Exception:
                pass

    def destroy(self):
        if self._dialog is not None:
            try:
                self._dialog.destroy()
            except Exception:
                pass

