        self.exam_date = exam_date
        self.last_study_date = None
        self.study_streak = 0   # Fixed typo: was study_steak
        self.load_streak_data()
        self.engine = StudyPlanEngine(
            self.exam_date,
            default_exam_date_to_today=False,
            module_id=self.module_id,
            module_title=self.module_title,
        )
        if str(getattr(self.engine, "module_id", "") or "").strip() != str(getattr(self, "module_id", "") or "").strip():
            raise RuntimeError(
                "Module isolation: engine.module_id must match app module_id. "
                "Check that load_preferences() sets module_id before engine creation."
            )
        self.engine.semantic_enabled = bool(self.semantic_enabled)
        self.engine.adaptive_quiz_prioritization = bool(self.adaptive_quiz_prioritization)
        self._tutor_session_controller = InMemoryTutorSessionController()
        self._tutor_learner_model_store = InMemoryTutorLearnerModelStore()
        self._module_adapter_registry = build_default_module_adapter_registry()
        self._module_adapter = self._resolve_active_module_adapter()
        _deterministic_practice = DeterministicTutorPracticeService(module_adapter=self._module_adapter)
        self._tutor_practice_service = AICapableTutorPracticeService(self, _deterministic_practice)
        self._tutor_assessment_service = DeterministicTutorAssessmentService()
        self._tutor_intervention_policy_service = DeterministicTutorInterventionPolicyService(
            module_adapter=self._module_adapter
        )
        self._tutor_struggle_policy_service = DeterministicTutorStrugglePolicyService()
        self._transfer_structure_registry = StructureRegistry()
        self._transfer_variant_generator = DeterministicTransferVariantGenerator()
        self._transfer_scoring_service = TransferScoringService()
        self._transfer_attempt_log_service = TransferAttemptLogService()
        self._transfer_attempts_log_loaded = False
        self._tutor_rag_evidence_policy_service = RuleBasedRagEvidencePolicyService()
        self._practice_loop_controller: PracticeLoopController | None = None
        self._tutor_learning_loop_service = RuleBasedTutorLearningLoopService(
            session_controller=self._tutor_session_controller,
            learner_model_store=self._tutor_learner_model_store,
            practice_service=self._tutor_practice_service,
            module_adapter=self._module_adapter,
            max_practice_items=2,
        )
        if self.exam_date is not None:
            self.engine.exam_date = self.exam_date
            try:
                self.engine.save_data()
            except Exception:
                pass
        else:
            if not os.path.exists(self.engine.DATA_FILE):
                self.engine.exam_date = None
        self.exam_date = self.engine.exam_date
        try:
            self.module_title = getattr(self.engine, "module_title", self.module_title)
            self.set_title(str(APP_DISPLAY_NAME))
        except Exception:
            pass
        try:
            self._load_section_c_question_bank()
        except Exception:
            self._section_c_question_bank = {}
            self._section_c_question_bank_loaded = False

        # Initialize performance caching and profiling services
        try:
            _initialize_performance_services()
            self._perf_profiler = _perf_integration.get_profiler()
            self._perf_cache = _perf_integration.get_cache_service()
            self._perf_middleware = _perf_integration.get_middleware()
        except Exception:
            self._perf_profiler = None
            self._perf_cache = None
            self._perf_middleware = None
        if self._perf_cache is None:
            from studyplan.components.performance.caching import PerformanceCacheService
            self._perf_cache = PerformanceCacheService(
                {"cache_max_size": 500, "default_ttl_seconds": 300, "cache_ttl": {}}
            )

        # Days to exam label
        self.days_label = Gtk.Label()
        self.days_label.set_halign(Gtk.Align.START)
        self._mark_critical_label(self.days_label)
        self.days_label.add_css_class("title")

        self._create_actions()
        self._add_module_actions_to_app()
        self.menu_bar = self._build_menu_bar()

        # Main layout
        hbox = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=12)
        hbox.add_css_class("workspace-split")
        hbox.set_margin_top(16)
        hbox.set_margin_bottom(16)
        hbox.set_margin_start(16)
        hbox.set_margin_end(16)
        self.main_box = hbox

        root = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=0)
        root.add_css_class("workspace-root")
        root.append(self.menu_bar)
        self.banner_revealer = Gtk.Revealer()
        self.banner_revealer.set_transition_type(Gtk.RevealerTransitionType.SLIDE_DOWN)
        self.banner_revealer.set_reveal_child(False)
        banner_box = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=8)
        banner_box.add_css_class("card")
        banner_box.add_css_class("banner")
        banner_box.add_css_class("banner-shell")
        banner_box.set_margin_start(16)
        banner_box.set_margin_end(16)
        banner_box.set_margin_top(6)
        banner_box.set_margin_bottom(0)
        self.banner_label = Gtk.Label(label="Pomodoro complete.")
        self.banner_label.set_halign(Gtk.Align.START)
        self.banner_label.set_wrap(False)
        self.banner_label.set_ellipsize(Pango.EllipsizeMode.END)
        self.banner_label.set_max_width_chars(96)
        self.banner_label.add_css_class("single-line-lock")
        self.banner_label.add_css_class("banner-text")
        self.banner_action_btn = Gtk.Button(label="Skip break")
        self.banner_action_btn.connect("clicked", lambda _b: self._skip_break_action())
        dismiss_btn = Gtk.Button(label="Dismiss")
        dismiss_btn.connect("clicked", lambda _b: self._hide_pomodoro_banner())
        banner_box.append(self.banner_label)
        banner_box.append(self.banner_action_btn)
        banner_box.append(dismiss_btn)
        self.banner_revealer.set_child(banner_box)
        root.append(self.banner_revealer)
        root.append(hbox)
        self.root_box = root
        self.set_child(root)

        # Left panel
        left_panel = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=12)
        left_panel.set_halign(Gtk.Align.FILL)
        left_panel.set_size_request(self._left_panel_width, -1)
