    def _build_workbench_shell(self, dashboard_scroll: Gtk.ScrolledWindow) -> Gtk.Box:
        shell = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=2)
        shell.add_css_class("panel")
        shell.add_css_class("panel-right")
        shell.add_css_class("workbench-shell")
        shell.set_hexpand(True)
        shell.set_vexpand(True)

        header = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=0)
        header.add_css_class("workbench-header")
        header.set_hexpand(True)
        header.set_halign(Gtk.Align.FILL)

        header_primary = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=6)
        header_primary.add_css_class("workbench-header-primary")
        header_primary.set_hexpand(True)
        header_primary.set_halign(Gtk.Align.FILL)

        title = Gtk.Label(label="Workspace")
        title.set_halign(Gtk.Align.START)
        title.set_hexpand(True)
        title.set_xalign(0.0)
        title.set_wrap(False)
        title.set_ellipsize(Pango.EllipsizeMode.NONE)
        title.add_css_class("section-title")
        title.add_css_class("workbench-title")
        header_primary.append(title)

        switcher = Gtk.StackSwitcher()
        switcher.add_css_class("workspace-tabs")
        switcher.set_halign(Gtk.Align.START)
        switcher.set_hexpand(False)

        tabs_row = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=0)
        tabs_row.set_hexpand(True)
        tabs_row.set_halign(Gtk.Align.FILL)
        tabs_left_spacer = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=0)
        tabs_left_spacer.set_hexpand(False)
        tabs_left_spacer.set_visible(False)
        tabs_row.append(tabs_left_spacer)
        tabs_row.append(switcher)
        tabs_right_spacer = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=0)
        tabs_right_spacer.set_hexpand(True)
        tabs_row.append(tabs_right_spacer)

        tabs_scroll = Gtk.ScrolledWindow()
        tabs_scroll.set_policy(Gtk.PolicyType.AUTOMATIC, Gtk.PolicyType.NEVER)
        tabs_scroll.set_hexpand(True)
        tabs_scroll.set_vexpand(False)
        tabs_scroll.set_propagate_natural_height(True)
        tabs_scroll.add_css_class("workspace-tabs-scroll")
        tabs_scroll.set_child(tabs_row)
        header.append(tabs_scroll)

        sidebar_btn = Gtk.Button(label="Sidebar")
        sidebar_btn.add_css_class("flat")
        sidebar_btn.add_css_class("sidebar-toggle")
        sidebar_btn.set_tooltip_text("Toggle left sidebar (Ctrl+B).")
        sidebar_btn.connect("clicked", lambda *_args: self._toggle_sidebar_visibility())
        header_primary.append(sidebar_btn)
        self.workbench_sidebar_btn = sidebar_btn
        header.prepend(header_primary)

        quick_actions_row = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=6)
        quick_actions_row.add_css_class("inline-toolbar")
        quick_actions_row.add_css_class("workbench-quick-actions")
        quick_actions_row.set_halign(Gtk.Align.START)
        quick_actions_row.set_hexpand(False)

        def _run_quick_action(action: Callable[[], Any]) -> None:
            try:
                action()
            except Exception:
                pass
            self._refresh_workbench_shell_status()

        quick_actions: list[tuple[str, Callable[[], Any], str, bool]] = [
            ("Focus 25m", lambda: self.on_focus_now(None), "Start a 25-minute focus block.", True),
            ("Quiz 8", lambda: self.on_quick_quiz(None), "Start a quick quiz session.", False),
            ("Review Due", lambda: self.on_clear_must_review(None), "Run due-review cleanup/apply action.", False),
            ("Coach Next", lambda: self.on_do_coach_next(None), "Apply the next coach action.", False),
        ]
        quick_action_button_labels: dict[Gtk.Button, tuple[str, str, str]] = {}
        for label_text, callback, tooltip, primary in quick_actions:
            btn = Gtk.Button(label=label_text)
            btn.set_halign(Gtk.Align.START)
            btn.set_hexpand(False)
            if primary:
                btn.add_css_class("suggested-action")
            else:
                btn.add_css_class("flat")
            btn.set_tooltip_text(tooltip)
            btn.connect("clicked", lambda *_args, cb=callback: _run_quick_action(cb))
            quick_actions_row.append(btn)
            short = {
                "Focus 25m": "Focus",
                "Quiz 8": "Quiz",
                "Review Due": "Review",
                "Coach Next": "Coach",
            }.get(label_text, label_text)
