    def _on_workbench_visible_page_changed(self, _stack: Gtk.Stack, _pspec: Any) -> None:
        page = ""
        try:
            current_stack = getattr(self, "workbench_stack", None)
            if current_stack is not None:
                page = str(current_stack.get_visible_child_name() or "")
        except Exception:
            page = ""
        self._refresh_workbench_page(page)

    def _refresh_workbench_shell_status(self) -> None:
        label = getattr(self, "workbench_status_label", None)
        if label is None:
            return
        try:
            window_width = int(self.get_width() or 0)
        except Exception:
            window_width = 0
        page_key = ""
        try:
            stack = getattr(self, "workbench_stack", None)
            if stack is not None:
                page_key = str(stack.get_visible_child_name() or "").strip().lower()
        except Exception:
            page_key = ""
        page_map = {
            "dashboard": "Dashboard",
            "tutor": "Tutor",
            "coach": "Coach",
            "insights": "Insights",
            "settings": "Settings",
        }
        page_title = str(page_map.get(page_key, "Workspace"))
        topic = str(getattr(self, "current_topic", "") or "").strip() or "No active topic"
        llm_enabled = bool(getattr(self, "local_llm_enabled", False))
        model_name = str(getattr(self, "local_llm_model", "") or "").strip()
        if not llm_enabled:
            model_label = "Local AI disabled"
        elif model_name:
            model_label = model_name
        else:
            model_label = "Auto-select"
        autopilot_enabled = bool(getattr(self, "ai_tutor_autopilot_enabled", True))
        autopilot_mode = self._coerce_ai_tutor_autonomy_mode(getattr(self, "ai_tutor_autonomy_mode", "assist"))
        semantic_enabled = bool(getattr(self, "semantic_enabled", False))
        if bool(getattr(self, "_sidebar_auto_hidden", False)):
            sidebar_state = "auto-hidden"
        else:
            sidebar_state = "shown" if self._is_sidebar_effectively_visible() else "hidden"
        status_tooltip = (
            f"{page_title} • Topic: {topic} • Model: {model_label} • "
            f"Autopilot: {'on' if autopilot_enabled else 'off'} ({autopilot_mode}) • "
            f"Semantic: {'on' if semantic_enabled else 'off'} • "
            f"Sidebar: {sidebar_state}"
        )
        try:
            rag_paths = self._get_rag_pdf_paths_for_reconfig()
            if not rag_paths:
                status_tooltip += "\nRAG: none — Add PDFs in Preferences → AI Tutor for better context."
        except Exception:
            pass
        narrow = bool(window_width and window_width <= 1180)
        compact = bool(window_width and window_width <= 1440)
        topic_short = self._compact_ui_token(topic, 20 if narrow else (26 if compact else 34), "No topic")
        model_short = self._compact_ui_token(model_label, 18 if narrow else (28 if compact else 38))
        ap_token = f"AP {'on' if autopilot_enabled else 'off'}:{autopilot_mode}"
        sem_token = f"Sem {'on' if semantic_enabled else 'off'}"
        sb_token = f"SB {sidebar_state}"
        if narrow:
            status_text = f"{page_title} • {topic_short} • {ap_token}"
        elif compact:
            status_text = f"{page_title} • {topic_short} • {model_short} • {ap_token} • {sem_token}"
        else:
            status_text = f"{page_title} • {topic_short} • {model_short} • {ap_token} • {sem_token} • {sb_token}"
        self._set_label_text_if_changed(label, status_text)
        try:
            label.set_tooltip_text(status_tooltip)
        except Exception:
            pass
        self._refresh_workbench_model_readiness_line()
        self._refresh_workbench_app_health_line()

    def _infer_local_model_source_label(self, model_name: str) -> str:
        name = str(model_name or "").strip().lower()
        if not name:
            return "Unknown"
        if name.startswith("gpt4all-"):
            return "GPT4All"
        return "Ollama"

    def _compute_workbench_model_readiness(self) -> tuple[str, str, str]:
        llm_enabled = bool(getattr(self, "local_llm_enabled", False))
        if not llm_enabled:
            return (
                "disabled",
                "Model: unavailable (disabled)",
                "Local AI tutor is disabled in Preferences.",
            )

        selected_model = str(getattr(self, "local_llm_model", "") or "").strip()
        cached_models = [
            str(item).strip()
            for item in list(getattr(self, "_ollama_models_cache", []) or [])
            if str(item or "").strip()
        ]
        current_model = selected_model or (cached_models[0] if cached_models else "")
        if not current_model:
            return (
                "unavailable",
                "Model: unavailable",
                "No local model detected. Open Tutor and click Refresh models.",
            )

        source = self._infer_local_model_source_label(current_model)
        cooling = False
        cooldown_remaining = 0
        cooldown_reader = getattr(self, "_is_local_llm_model_on_cooldown", None)
        if callable(cooldown_reader):
            try:
                cooling, cooldown_remaining, _cooldown_reason = cast(Any, cooldown_reader(current_model))
            except Exception:
                cooling, cooldown_remaining = False, 0
        if cooling:
            return (
                "recovering",
                f"Model: {source} recovering ({int(max(1, cooldown_remaining))}s)",
                f"{source} model is cooling down after recent failures: {current_model}",
            )

        if selected_model and cached_models and selected_model not in cached_models:
            return (
                "not_loaded",
                f"Model: {source} not loaded",
                f"Selected model is not currently available in Ollama: {selected_model}",
            )

        if bool(getattr(self, "_gpt4all_auto_import_in_progress", False)):
            return (
                "syncing",
                f"Model: {source} syncing",
                f"Model catalog is syncing/importing in background. Current model: {current_model}",
            )

        return (
            "ready",
            f"Model: {source} ready",
            f"Current local model is ready: {current_model}",
        )

    def _refresh_workbench_model_readiness_line(self) -> None:
        label = getattr(self, "workbench_model_label", None)
        if label is None:
            return
        state_key, status_text, status_tooltip = self._compute_workbench_model_readiness()
        self._set_label_text_if_changed(label, status_text)
        try:
            if str(state_key or "").strip().lower() == "ready":
                label.remove_css_class("status-warn")
            else:
                label.add_css_class("status-warn")
        except Exception:
            pass
        try:
            label.set_tooltip_text(status_tooltip)
        except Exception:
            pass

    def _compute_workbench_app_health(self) -> tuple[str, str, str]:
        sync_in_progress = bool(getattr(self, "_coach_sync_in_progress", False))
        sync_key = str(getattr(self, "_last_coach_sync_key", "") or "").strip()
        if sync_in_progress or sync_key:
            origin = str(getattr(self, "_last_coach_sync_origin", "") or "").strip()
            detail = f" (origin: {origin})" if origin else ""
            return (
                "sync_issue",
                "App Health: Sync issue",
                f"Coach views are resyncing topic picks{detail}.",
            )

        llm_enabled = bool(getattr(self, "local_llm_enabled", False))
        selected_model = str(getattr(self, "local_llm_model", "") or "").strip()
        cached_models = [
            str(item).strip()
            for item in list(getattr(self, "_ollama_models_cache", []) or [])
            if str(item or "").strip()
        ]
        if not llm_enabled:
            return (
                "model_unavailable",
                "App Health: Model unavailable",
                "Local AI tutor is disabled in Preferences.",
            )
        if not selected_model and not cached_models:
            return (
                "model_unavailable",
                "App Health: Model unavailable",
                "No local AI model is currently ready. Open Tutor and refresh models.",
            )

        coach_error = str(getattr(self, "_ai_coach_last_error", "") or "").strip()
        cooling_models = 0
        recovering_models = 0
        now_ts = float(time.monotonic())
        model_health = getattr(self, "_llm_model_health", {})
        if isinstance(model_health, dict):
            for row in list(model_health.values()):
                if not isinstance(row, dict):
                    continue
                try:
                    cooldown_until = float(row.get("cooldown_until", 0.0) or 0.0)
                except Exception:
                    cooldown_until = 0.0
                consecutive_failures = int(row.get("consecutive_failures", 0) or 0)
                row_error = str(row.get("last_error", "") or "").strip()
                if cooldown_until > now_ts:
                    cooling_models += 1
                elif consecutive_failures > 0 or row_error:
                    recovering_models += 1
        if coach_error or cooling_models > 0 or recovering_models > 0:
            parts: list[str] = []
            if cooling_models > 0:
                parts.append(f"{cooling_models} model cooling down")
            if recovering_models > 0:
                parts.append(f"{recovering_models} model recovering")
            if coach_error:
                parts.append("coach fallback active")
            detail = ", ".join(parts) if parts else "recent model issue detected"
            return (
                "recovery_mode",
                "App Health: Recovery mode",
                f"Tutor is recovering ({detail}). Study can continue safely.",
            )

        return ("ready", "App Health: Ready", "Core study features are available.")

    def _refresh_workbench_app_health_line(self) -> None:
        label = getattr(self, "workbench_health_label", None)
        if label is None:
            return
        status_key, status_text, status_tooltip = self._compute_workbench_app_health()
        self._set_label_text_if_changed(label, status_text)
        try:
            if str(status_key or "").strip().lower() == "ready":
                label.remove_css_class("status-warn")
            else:
                label.add_css_class("status-warn")
        except Exception:
            pass
        try:
            label.set_tooltip_text(status_tooltip)
        except Exception:
            pass

    def _refresh_workbench_page(self, page: str) -> None:
        key = str(page or "").strip().lower()
        refresh_map: dict[str, tuple[str, Callable[[], Any]]] = {
            "tutor": ("tutor_workspace", self._refresh_tutor_workspace_page),
            "coach": ("coach_workspace", self._refresh_coach_workspace_page),
            "insights": ("insights_workspace", self._refresh_insights_workspace_page),
            "settings": ("settings_workspace", self._refresh_settings_workspace_page),
        }
        target = refresh_map.get(key)
        if target is not None:
            section_id, refresh_fn = target
            self._safe_render_section(
                section_id,
                lambda: refresh_fn(),
                fallback_fn=lambda report, page_key=key: self._set_workbench_refresh_fallback(page_key, report),
            )
        self._refresh_workbench_shell_status()

    def _open_workspace_tab(self, page: str, *, present: bool = True) -> bool:
        stack = getattr(self, "workbench_stack", None)
        if stack is None:
            return False
        alias = str(page or "").strip().lower()
        if not alias:
            return False
        target = str(getattr(self, "_workbench_aliases", {}).get(alias, alias) or "").strip().lower()
        if target not in set(getattr(self, "_workbench_page_names", set()) or set()):
            return False
        try:
            stack.set_visible_child_name(target)
        except Exception:
            return False
        self._refresh_workbench_page(target)
        if present:
            try:
                self.present()
            except Exception:
                pass
        return True

