    def _refresh_settings_workspace_page(self) -> None:
        llm_enabled = getattr(self, "_settings_workspace_llm_enabled_toggle", None)
        llm_auto_select = getattr(self, "_settings_workspace_auto_select_toggle", None)
        semantic_enabled = getattr(self, "_settings_workspace_semantic_toggle", None)
        autopilot_enabled = getattr(self, "_settings_workspace_autopilot_toggle", None)
        notifications = getattr(self, "_settings_workspace_notifications_toggle", None)
        modern_toggle = getattr(self, "_settings_workspace_modern_toggle", None)
        sidebar_toggle = getattr(self, "_settings_workspace_sidebar_toggle", None)
        reduce_motion = getattr(self, "_settings_workspace_reduce_motion_toggle", None)
        mode_dropdown = getattr(self, "_settings_workspace_mode_dropdown", None)
        if (
            llm_enabled is None
            or llm_auto_select is None
            or semantic_enabled is None
            or autopilot_enabled is None
            or notifications is None
            or modern_toggle is None
            or sidebar_toggle is None
            or reduce_motion is None
            or mode_dropdown is None
        ):
            return
        llm_enabled.set_active(bool(getattr(self, "local_llm_enabled", True)))
        llm_auto_select.set_active(bool(getattr(self, "local_llm_auto_select", DEFAULT_OLLAMA_AUTO_SELECT)))
        semantic_enabled.set_active(bool(getattr(self, "semantic_enabled", True)))
        autopilot_enabled.set_active(bool(getattr(self, "ai_tutor_autopilot_enabled", True)))
        notifications.set_active(bool(getattr(self, "notifications_enabled", True)))
        modern_locked = bool(UI_MODERN_HARD_LOCK)
        modern_toggle.set_active(bool(getattr(self, "ui_modern_enabled", DEFAULT_UI_MODERN_ENABLED)))
        modern_toggle.set_sensitive(not modern_locked)
        if modern_locked:
            modern_toggle.set_tooltip_text("Modern workspace is locked on in this build.")
        else:
            modern_toggle.set_tooltip_text(None)
        sidebar_toggle.set_active(bool(getattr(self, "ui_sidebar_visible", DEFAULT_UI_SIDEBAR_VISIBLE)))
        reduce_motion.set_active(bool(getattr(self, "ui_reduce_motion", DEFAULT_UI_REDUCE_MOTION)))
        mode = self._coerce_ai_tutor_autonomy_mode(getattr(self, "ai_tutor_autonomy_mode", AI_TUTOR_DEFAULT_AUTONOMY_MODE))
        mapping = {"suggest": 0, "assist": 1, "cockpit": 2}
        mode_dropdown.set_selected(int(mapping.get(mode, 1)))
        self._refresh_workbench_shell_status()

    def _apply_settings_workspace_changes(self) -> None:
        llm_enabled = getattr(self, "_settings_workspace_llm_enabled_toggle", None)
        llm_auto_select = getattr(self, "_settings_workspace_auto_select_toggle", None)
        semantic_enabled = getattr(self, "_settings_workspace_semantic_toggle", None)
        autopilot_enabled = getattr(self, "_settings_workspace_autopilot_toggle", None)
        notifications = getattr(self, "_settings_workspace_notifications_toggle", None)
        modern_toggle = getattr(self, "_settings_workspace_modern_toggle", None)
        sidebar_toggle = getattr(self, "_settings_workspace_sidebar_toggle", None)
        reduce_motion = getattr(self, "_settings_workspace_reduce_motion_toggle", None)
        mode_dropdown = getattr(self, "_settings_workspace_mode_dropdown", None)
        status_label = getattr(self, "_settings_workspace_status_label", None)
        if (
            llm_enabled is None
            or llm_auto_select is None
            or semantic_enabled is None
            or autopilot_enabled is None
            or notifications is None
            or modern_toggle is None
            or sidebar_toggle is None
            or reduce_motion is None
            or mode_dropdown is None
        ):
            return
        self.local_llm_enabled = bool(llm_enabled.get_active())
        self.local_llm_auto_select = self._coerce_local_llm_auto_select(llm_auto_select.get_active())
        semantic_requested = bool(semantic_enabled.get_active())
        self.notifications_enabled = bool(notifications.get_active())
        self.ai_tutor_autopilot_enabled = bool(autopilot_enabled.get_active())
        if bool(UI_MODERN_HARD_LOCK):
            self.ui_modern_enabled = True
            self.ui_legacy_fallback_enabled = False
        else:
            self.ui_modern_enabled = bool(modern_toggle.get_active())
        self.ui_sidebar_visible = bool(sidebar_toggle.get_active())
        self.ui_reduce_motion = bool(reduce_motion.get_active())
        mode_idx = int(mode_dropdown.get_selected())
        mode_map = {0: "suggest", 1: "assist", 2: "cockpit"}
        self.ai_tutor_autonomy_mode = self._coerce_ai_tutor_autonomy_mode(mode_map.get(mode_idx, "assist"))
        self._restart_ai_tutor_global_autopilot_timer()
        self._set_semantic_enabled(semantic_requested, persist=False)
        self._refresh_ui_style_runtime()
        self.save_preferences()
        self._refresh_tutor_workspace_page()
        self._refresh_coach_workspace_page()
        self._refresh_insights_workspace_page()
        self._refresh_settings_workspace_page()
        if status_label is not None:
            self._set_label_text_if_changed(status_label, "Applied. Settings saved.")

    def _open_preferences_dialog_force(self) -> None:
        """Open the full modal Preferences dialog (e.g. from Settings workspace 'Open Full Preferences' button)."""
        self.on_open_preferences(None, None)

    def _close_tracked_ui_dialogs(self) -> int:
        lifecycle = getattr(self, "_ui_dialog_lifecycle", None)
        if lifecycle is None:
            return 0
        try:
            count = int(getattr(lifecycle, "count", lambda: 0)() or 0)
        except Exception:
            count = 0
        try:
            lifecycle.close_all()
        except Exception:
            pass
        return max(0, count)

    def _run_ui_stability_repair(self) -> tuple[bool, str]:
        failed_steps: list[str] = []

        scheduler = getattr(self, "_ui_refresh_scheduler", None)
        if scheduler is not None:
            try:
                scheduler.cancel_all()
            except Exception:
                failed_steps.append("refresh-queue")

        try:
            self._refresh_ui_style_runtime()
        except Exception:
            failed_steps.append("theme-runtime")
        try:
            self._apply_current_layout_mode()
        except Exception:
            failed_steps.append("layout-mode")
        try:
            self._apply_sidebar_visibility(persist=False, announce=False)
        except Exception:
            failed_steps.append("sidebar-state")
        try:
            self._refresh_tutor_workspace_page()
            self._refresh_coach_workspace_page()
            self._refresh_insights_workspace_page()
            self._refresh_settings_workspace_page()
        except Exception:
            failed_steps.append("workspace-refresh")
        try:
            self.update_study_room_card()
            self.update_dashboard()
        except Exception:
            failed_steps.append("dashboard-refresh")

        if failed_steps:
            steps = ", ".join(failed_steps[:4])
            if len(failed_steps) > 4:
                steps += ", …"
            return False, f"Stability repair partial: {steps}"
        return True, "Stability repair complete."

    def on_toggle_menu_shortcut(self, *_args):
        self.toggle_menu_bar()
        return True

    def on_toggle_menu_action(self, _action, _param):
        self.toggle_menu_bar()

    def on_toggle_sidebar_shortcut(self, *_args):
        self._toggle_sidebar_visibility()
        return True

    def on_toggle_sidebar_action(self, _action, _param):
        self._toggle_sidebar_visibility()

    def _sync_semantic_action_state(self) -> None:
        try:
            action = self.lookup_action("semantic_enabled")
            if action is None:
                return
            current = bool(self.semantic_enabled)
            state = action.get_state()
            if state is None or bool(state.get_boolean()) != current:
                action.set_state(GLib.Variant.new_boolean(current))
        except Exception:
            pass

    def _set_semantic_enabled(self, enabled: bool, persist: bool = True) -> None:
        enabled = bool(enabled)
        self.semantic_enabled = enabled
        try:
            self.engine.semantic_enabled = enabled
        except Exception:
            pass
        self._sync_semantic_action_state()
        if enabled:
            self._warmup_semantic_engine_async()
        try:
            self.update_study_room_card()
        except Exception:
            pass
        try:
            self.update_dashboard()
        except Exception:
            pass
        if persist:
            self.save_preferences()

    def on_toggle_semantic_action(self, action, value) -> None:
        enabled = bool(value.get_boolean()) if isinstance(value, GLib.Variant) else (not bool(self.semantic_enabled))
        try:
            action.set_state(GLib.Variant.new_boolean(enabled))
        except Exception:
            pass
        self._set_semantic_enabled(enabled, persist=True)
        self.send_notification(
            "Semantic Routing",
            "Enabled" if enabled else "Disabled (deterministic fallback only)",
        )

    def toggle_menu_bar(self) -> None:
        self.menu_bar_visible = not self.menu_bar_visible
        self.menu_bar.set_visible(self.menu_bar_visible)
        self.save_preferences()

    def _apply_sidebar_visibility(self, *, persist: bool = False, announce: bool = False) -> None:
        visible = self._is_sidebar_effectively_visible()
        auto_hidden = bool(getattr(self, "_sidebar_auto_hidden", False))
        revealer = getattr(self, "left_sidebar_revealer", None)
        left_scroll = getattr(self, "left_scroll", None)
        if revealer is not None:
            try:
                revealer.set_visible(True if visible else False)
            except Exception:
                pass
            try:
                revealer.set_reveal_child(visible)
            except Exception:
                pass
        if left_scroll is not None:
            try:
                left_scroll.set_visible(visible)
            except Exception:
                pass
        self._refresh_workbench_sidebar_button_presentation()
        try:
            shell = getattr(self, "workbench_shell", None)
            if visible:
                if shell is not None:
                    shell.remove_css_class("sidebar-collapsed")
                self.remove_css_class("sidebar-collapsed")
            else:
                if shell is not None:
                    shell.add_css_class("sidebar-collapsed")
                self.add_css_class("sidebar-collapsed")
        except Exception:
            pass
        self._refresh_workspace_split_spacing()
        self._refresh_workbench_tabs_alignment()
        try:
            self._refresh_workbench_shell_status()
        except Exception:
            pass
        if persist:
            try:
                self.save_preferences()
            except Exception:
                pass
        if announce:
            self.send_notification("Workspace Sidebar", "Shown." if visible else "Hidden.")

    def _refresh_workbench_sidebar_button_presentation(self) -> None:
        button = getattr(self, "workbench_sidebar_btn", None)
        if button is None:
            return
        auto_hidden = bool(getattr(self, "_sidebar_auto_hidden", False))
        visible = self._is_sidebar_effectively_visible()
        try:
            width = int(self.get_width() or 0)
        except Exception:
            width = 0
        compact_btn = bool(getattr(self, "_tile_mode", False) or getattr(self, "_stack_layout_active", False))
        if width > 0:
            compact_btn = compact_btn or width <= 1280
        try:
            if auto_hidden:
                button.set_label("Auto")
                button.set_tooltip_text("Sidebar is auto-collapsed in narrow/tile layout.")
                button.set_sensitive(False)
                return
            if compact_btn:
                button.set_label("Hide" if visible else "Show")
            else:
                button.set_label("Sidebar")
            if visible:
                button.set_tooltip_text("Hide left sidebar (Ctrl+B).")
            else:
                button.set_tooltip_text("Show left sidebar (Ctrl+B).")
            button.set_sensitive(True)
        except Exception:
            pass
        try:
            self._refresh_workbench_header_compact_layout()
        except Exception:
            pass

    def _refresh_workbench_header_compact_layout(self) -> None:
        row = getattr(self, "_workbench_quick_actions_row", None)
        labels_map = getattr(self, "_workbench_quick_action_button_labels", None)
        scroll = getattr(self, "_workbench_quick_actions_scroll", None)
        if row is None or not isinstance(labels_map, dict):
            return
        try:
            width = int(self.get_width() or 0)
        except Exception:
            width = 0
        narrow = bool(getattr(self, "_tile_mode", False) or getattr(self, "_stack_layout_active", False))
        if width > 0:
            narrow = narrow or width <= 1320
        very_narrow = bool(getattr(self, "_tile_mode", False))
        if width > 0:
            very_narrow = very_narrow or width <= 1080
        try:
            row.set_orientation(Gtk.Orientation.HORIZONTAL)
        except Exception:
            pass
        try:
            row.set_spacing(4 if very_narrow else 6)
        except Exception:
            pass
        try:
            row.set_halign(Gtk.Align.START)
            row.set_hexpand(False)
        except Exception:
            pass
        for btn, labels in list(labels_map.items()):
            if not isinstance(labels, tuple) or len(labels) < 3:
                continue
            full_label, short_label, tiny_label = labels
            chosen = tiny_label if very_narrow else (short_label if narrow else full_label)
            try:
                btn.set_label(str(chosen or full_label))
            except Exception:
                pass
            try:
                btn.set_halign(Gtk.Align.START)
                btn.set_hexpand(False)
            except Exception:
                pass
        if scroll is not None:
            try:
                scroll.set_min_content_height(40)
                scroll.set_policy(Gtk.PolicyType.AUTOMATIC, Gtk.PolicyType.NEVER)
            except Exception:
                pass

    def _toggle_sidebar_visibility(self, *, persist: bool = True) -> None:
        self.ui_sidebar_visible = not bool(getattr(self, "ui_sidebar_visible", True))
        self._apply_sidebar_visibility(persist=persist, announce=False)

    def _detect_tiling_wm_hint(self) -> bool:
        markers = ("HYPRLAND_INSTANCE_SIGNATURE", "SWAYSOCK", "I3SOCK")
        for name in markers:
            if str(os.environ.get(name, "") or "").strip():
                return True
        session_name = str(os.environ.get("XDG_CURRENT_DESKTOP", "") or "").strip().lower()
        return session_name in {"hyprland", "sway", "i3"}

    def _is_sidebar_effectively_visible(self) -> bool:
        return bool(getattr(self, "ui_sidebar_visible", True)) and not bool(
            getattr(self, "_sidebar_auto_hidden", False)
        )

    def _refresh_workspace_split_spacing(self) -> None:
        box = getattr(self, "main_box", None)
        if box is None:
            return
        try:
            if box.get_orientation() != Gtk.Orientation.HORIZONTAL:
                return
        except Exception:
            return
        base_spacing = 10 if bool(getattr(self, "_tile_mode", False)) else 12
        effective_visible = self._is_sidebar_effectively_visible()
        try:
            box.set_spacing(base_spacing if effective_visible else 0)
        except Exception:
            pass

    def _refresh_workbench_tabs_alignment(self) -> None:
        switcher = getattr(self, "workbench_switcher", None)
        left_spacer = getattr(self, "workbench_tabs_left_spacer", None)
        right_spacer = getattr(self, "workbench_tabs_right_spacer", None)
        tabs_scroll = getattr(self, "workbench_tabs_scroll", None)
        if switcher is None:
            return
        center_tabs = not self._is_sidebar_effectively_visible()
        try:
            switcher.set_halign(Gtk.Align.CENTER if center_tabs else Gtk.Align.START)
        except Exception:
            pass
        if left_spacer is not None:
            try:
                left_spacer.set_visible(center_tabs)
            except Exception:
                pass
            try:
                left_spacer.set_hexpand(center_tabs)
            except Exception:
                pass
        if right_spacer is not None:
            try:
                right_spacer.set_hexpand(True)
            except Exception:
                pass
        if tabs_scroll is not None:
            try:
                if center_tabs:
                    tabs_scroll.add_css_class("tabs-centered")
                else:
                    tabs_scroll.remove_css_class("tabs-centered")
            except Exception:
                pass

    def _should_auto_hide_sidebar(self, width: int, height: int, *, stack_layout: bool, tile_mode: bool) -> bool:
        if bool(stack_layout):
            return True
        if bool(tile_mode) and int(width) <= 1360:
            return True
        return int(width) <= 980 or int(height) <= 700

    def _set_main_box_child_order(self, stack_layout: bool) -> None:
        box = getattr(self, "main_box", None)
        sidebar = getattr(self, "left_sidebar_revealer", None)
        shell = getattr(self, "workbench_shell", None)
        if box is None or sidebar is None or shell is None:
            return
        try:
            if bool(stack_layout):
                box.reorder_child_after(shell, None)
                box.reorder_child_after(sidebar, shell)
            else:
                box.reorder_child_after(sidebar, None)
                box.reorder_child_after(shell, sidebar)
        except Exception:
            pass

    def _apply_sidebar_adaptive_policy(self, width: int, height: int, *, stack_layout: bool, tile_mode: bool) -> None:
        auto_hide = self._should_auto_hide_sidebar(width, height, stack_layout=stack_layout, tile_mode=tile_mode)
        previous = bool(getattr(self, "_sidebar_auto_hidden", False))
        self._sidebar_auto_hidden = bool(auto_hide)
        if previous != bool(auto_hide):
            self._apply_sidebar_visibility(persist=False, announce=False)

