    def _apply_snapshot_import_result(self, result: dict[str, Any], title_prefix: str) -> None:
        self.exam_date = self.engine.exam_date
        self.update_exam_date_display()
        self.update_availability_display()
        self.update_recommendations()
        self.update_study_room_card()
        self.update_dashboard()
        msg = (
            f"{title_prefix}\n\n"
            f"Chapters: {int(result.get('chapters', 0) or 0)}\n"
            f"Study days: {int(result.get('study_days', 0) or 0)}\n"
            f"Quiz results: {int(result.get('quiz_results', 0) or 0)}\n"
            f"Progress points: {int(result.get('progress_points', 0) or 0)}"
        )
        snapshot_path = result.get("snapshot_path")
        if isinstance(snapshot_path, str) and snapshot_path:
            msg += f"\nSource: {os.path.basename(snapshot_path)}"
        ok = self._new_message_dialog(
            transient_for=self,
            modal=True,
            message_type=Gtk.MessageType.INFO,
            buttons=Gtk.ButtonsType.OK,
            text=msg,
        )
        ok.connect("response", lambda d, _r: d.destroy())
        ok.present()

    def on_restore_latest_snapshot(self, _button):
        try:
            snapshot_path = self.engine.get_latest_backup_snapshot_path()
            if not snapshot_path:
                raise FileNotFoundError("No backup snapshot available.")
            snapshot_path = self._validate_import_source_path(snapshot_path, "Snapshot", (".json", ".bak"))
        except Exception as e:
            err = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.ERROR,
                buttons=Gtk.ButtonsType.OK,
                text=f"Restore failed: {e}",
            )
            err.connect("response", lambda d, _r: d.destroy())
            err.present()
            return
        try:
            modified = datetime.datetime.fromtimestamp(os.path.getmtime(snapshot_path)).strftime("%Y-%m-%d %H:%M:%S")
        except Exception:
            modified = "unknown"
        confirm = self._new_message_dialog(
            transient_for=self,
            modal=True,
            message_type=Gtk.MessageType.QUESTION,
            buttons=Gtk.ButtonsType.YES_NO,
            text=(
                "Restore latest snapshot?\n\n"
                f"File: {os.path.basename(snapshot_path)}\n"
                f"Modified: {modified}"
            ),
        )

        def _on_confirm(dlg, resp):
            dlg.destroy()
            if resp != Gtk.ResponseType.YES:
                return
            try:
                result = self.engine.restore_latest_snapshot()
                self._apply_snapshot_import_result(result, title_prefix="Latest snapshot restored.")
            except Exception as e:
                self._log_error("restore_latest_snapshot", e)
                err = self._new_message_dialog(
                    transient_for=self,
                    modal=True,
                    message_type=Gtk.MessageType.ERROR,
                    buttons=Gtk.ButtonsType.OK,
                    text=f"Restore failed: {e}",
                )
                err.connect("response", lambda dd, _r: dd.destroy())
                err.present()

        confirm.connect("response", _on_confirm)
        confirm.present()

    def on_recover_snapshot_picker(self, _button):
        try:
            snapshots = self.engine.list_backup_snapshots(limit=50)
        except Exception as e:
            err = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.ERROR,
                buttons=Gtk.ButtonsType.OK,
                text=f"Snapshot list failed: {e}",
            )
            err.connect("response", lambda d, _r: d.destroy())
            err.present()
            return

        if not snapshots:
            info = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.INFO,
                buttons=Gtk.ButtonsType.OK,
                text="No snapshot backups available yet.",
            )
            info.connect("response", lambda d, _r: d.destroy())
            info.present()
            return

        def _fmt_size(num_bytes: int) -> str:
            size = float(max(0, int(num_bytes or 0)))
            units = ["B", "KB", "MB", "GB"]
            for unit in units:
                if size < 1024.0 or unit == units[-1]:
                    return f"{size:.0f}{unit}" if unit == "B" else f"{size:.1f}{unit}"
                size /= 1024.0
            return "0B"

        entries: list[tuple[str, str]] = []
        for item in snapshots:
            path = str(item.get("path", "") or "")
            if not path:
                continue
            name = str(item.get("name", os.path.basename(path)) or os.path.basename(path))
            modified = str(item.get("modified", "unknown") or "unknown")
            size_label = _fmt_size(int(item.get("size_bytes", 0) or 0))
            latest = " [latest]" if bool(item.get("is_latest")) else ""
            label = f"{name}{latest}  |  {modified}  |  {size_label}"
            entries.append((path, label))

        if not entries:
            info = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.INFO,
                buttons=Gtk.ButtonsType.OK,
                text="No valid snapshot backups available.",
            )
            info.connect("response", lambda d, _r: d.destroy())
            info.present()
            return

        dialog = self._new_dialog(title="Recover from Snapshot", transient_for=self, modal=True)
        dialog.add_buttons("_Cancel", Gtk.ResponseType.CANCEL, "_Recover", Gtk.ResponseType.OK)
        content = dialog.get_content_area()
        content.set_spacing(8)
        last_modified = str(snapshots[0].get("modified", "unknown") or "unknown") if snapshots else "unknown"
        last_label = Gtk.Label(label=f"Last snapshot: {last_modified}")
        last_label.set_halign(Gtk.Align.START)
        last_label.add_css_class("muted")
        content.append(last_label)
        title = Gtk.Label(label="Select snapshot to recover:")
        title.set_halign(Gtk.Align.START)
        title.add_css_class("muted")
        content.append(title)

        snapshot_list = Gtk.StringList.new([entry[1] for entry in entries])
        snapshot_combo = Gtk.DropDown.new(snapshot_list, None)
        snapshot_combo.set_halign(Gtk.Align.FILL)
        snapshot_combo.set_hexpand(True)
        snapshot_combo.set_selected(0)
        content.append(snapshot_combo)

        caution = Gtk.Label(
            label="This replaces current in-memory progress with the selected snapshot and saves it."
        )
        caution.set_halign(Gtk.Align.START)
        caution.set_wrap(True)
        caution.add_css_class("warning")
        content.append(caution)

        def _on_response(dlg, resp):
            dlg.destroy()
            if resp != Gtk.ResponseType.OK:
                return
            try:
                selected = int(snapshot_combo.get_selected())
            except Exception:
                selected = 0
            if selected < 0 or selected >= len(entries):
                selected = 0
            path = entries[selected][0]
            try:
                path = self._validate_import_source_path(path, "Snapshot", (".json", ".bak"))
                result = self.engine.import_data_snapshot(path)
                result["snapshot_path"] = path
                self._apply_snapshot_import_result(result, title_prefix="Snapshot recovered.")
            except Exception as e:
                self._log_error("recover_snapshot_picker", e)
                err = self._new_message_dialog(
                    transient_for=self,
                    modal=True,
                    message_type=Gtk.MessageType.ERROR,
                    buttons=Gtk.ButtonsType.OK,
                    text=f"Recover failed: {e}",
                )
                err.connect("response", lambda dd, _r: dd.destroy())
                err.present()

        dialog.connect("response", _on_response)
        dialog.present()


