    def on_export_template_response(self, dialog, response):
        if response != Gtk.ResponseType.ACCEPT:
            dialog.destroy()
            return

        file_path = self._get_file_path(dialog)
        dialog.destroy()

        if not file_path:
            return

        json_template = {
            "chapter": "DCF Methods",
            "questions": [
                {
                    "question": "What is the main advantage of NPV?",
                    "options": ["Considers time value", "Easy to compute", "Ignores risk", "Uses profit"],
                    "correct": "Considers time value",
                    "explanation": "NPV discounts cash flows to present value.",
                    "outcome_ids": ["dcf_1"]
                }
            ]
        }

        csv_template = (
            "chapter,question,option1,option2,option3,option4,correct,explanation,outcome_ids\n"
            "DCF Methods,What is the main advantage of NPV?,Considers time value,Easy to compute,Ignores risk,Uses profit,Considers time value,NPV discounts cash flows to present value.,dcf_1\n"
        )

        try:
            file_path = self._prepare_export_target_path(
                file_path,
                "Template export",
                default_extension=".json",
                allowed_extensions=(".json", ".csv"),
            )
            if file_path.lower().endswith(".csv"):
                self._atomic_write_text_file(file_path, csv_template)
            else:
                json_text = json.dumps(json_template, indent=2, ensure_ascii=False) + "\n"
                self._atomic_write_text_file(file_path, json_text)

            success_dialog = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.INFO,
                buttons=Gtk.ButtonsType.OK,
                text="Template exported successfully."
            )
            success_dialog.connect("response", lambda d, r: d.destroy())
            success_dialog.present()
        except Exception as e:
            error_dialog = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.ERROR,
                buttons=Gtk.ButtonsType.OK,
                text=f"Error exporting template: {e}"
            )
            error_dialog.connect("response", lambda d, r: d.destroy())
            error_dialog.present()

    def on_export_question_stats(self, _button):
        if getattr(self, "_dialog_smoke_mode", False):
            dialog = self._harden_window(Gtk.FileChooserDialog(  # gtk4_lint:ignore
                title="Export Question Stats (CSV)",
                transient_for=self,
                action=Gtk.FileChooserAction.SAVE,
            ))
            dialog.add_buttons(
                "_Cancel", Gtk.ResponseType.CANCEL, "_Save", Gtk.ResponseType.ACCEPT
            )
            dialog.connect("response", self.on_export_question_stats_response)
            dialog.present()
            return
        dialog = Gtk.FileChooserNative(
            title="Export Question Stats (CSV)",
            transient_for=self,
            action=Gtk.FileChooserAction.SAVE,
            accept_label="_Save",
            cancel_label="_Cancel",
        )
        self._active_native_dialog = dialog
        dialog.connect("response", self.on_export_question_stats_response)
        dialog.connect("response", lambda *_args: setattr(self, "_active_native_dialog", None))
        dialog.show()

    def on_export_question_stats_response(self, dialog, response):
        if response != Gtk.ResponseType.ACCEPT:
            dialog.destroy()
            return
        file_path = self._get_file_path(dialog)
        dialog.destroy()
        try:
            if not file_path:
                raise ValueError("No file selected.")
            file_path = self._prepare_export_target_path(
                file_path,
                "Question stats export",
                default_extension=".csv",
                allowed_extensions=(".csv",),
            )
            stats = getattr(self.engine, "question_stats", {}) or {}
            questions = getattr(self.engine, "QUESTIONS", {}) or {}
            rows: list[list[Any]] = [[
                "Chapter",
                "Question Index",
                "Question",
                "Attempts",
                "Correct",
                "Miss Rate",
                "Streak",
                "Avg Time (sec)",
                "Last Time (sec)",
                "Last Seen",
                "Outcome IDs",
                "Quality Score",
                "Quality Issues",
                "Difficulty Guess",
                "Max Distractor Similarity",
            ]]
            for chapter, chapter_stats in stats.items():
                if not isinstance(chapter_stats, dict):
                    continue
                q_list = questions.get(chapter, []) if isinstance(questions, dict) else []
                for key, entry in chapter_stats.items():
                    if not isinstance(entry, dict):
                        continue
                    try:
                        idx = int(key)
                    except Exception:
                        continue
                    q_text = ""
                    outcome_ids_str = ""
                    if isinstance(q_list, list) and 0 <= idx < len(q_list):
                        try:
                            q_obj = q_list[idx]
                            q_text = str(q_obj.get("question", ""))
                            oids = q_obj.get("outcome_ids")
                            if isinstance(oids, list) and oids:
                                outcome_ids_str = "|".join(str(x) for x in oids)
                            quality = assess_question_quality_extended(q_obj)
                        except Exception:
                            q_text = ""
                            quality = {}
                    else:
                        quality = {}
                    try:
                        attempts = int(entry.get("attempts", 0) or 0)
                    except Exception:
                        attempts = 0
                    try:
                        correct = int(entry.get("correct", 0) or 0)
                    except Exception:
                        correct = 0
                    miss_rate = 0.0 if attempts <= 0 else 1.0 - (correct / max(1, attempts))
                    try:
                        streak = int(entry.get("streak", 0) or 0)
                    except Exception:
                        streak = 0
                    try:
                        avg_time = float(entry.get("avg_time_sec", 0) or 0.0)
                    except Exception:
                        avg_time = 0.0
                    try:
                        last_time = float(entry.get("last_time_sec", 0) or 0.0)
                    except Exception:
                        last_time = 0.0
                    last_seen = entry.get("last_seen") or ""
                    rows.append(
                        [
                            chapter,
                            idx,
                            q_text,
                            attempts,
                            correct,
                            f"{miss_rate:.2f}",
                            streak,
                            f"{avg_time:.1f}",
                            f"{last_time:.1f}",
                            last_seen,
                            outcome_ids_str,
                            f"{float(quality.get('score', 0.0) or 0.0):.2f}",
                            "|".join(str(x) for x in (quality.get("issues") or [])),
                            str(quality.get("difficulty_guess", "") or ""),
                            f"{float(quality.get('max_distractor_similarity', 0.0) or 0.0):.2f}",
                        ]
                    )
            self._atomic_write_csv_rows(file_path, rows)
            success_dialog = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.INFO,
                buttons=Gtk.ButtonsType.OK,
                text="Question stats exported successfully.",
            )
            success_dialog.connect("response", lambda d, r: d.destroy())
            success_dialog.present()
        except Exception as e:
            error_dialog = self._new_message_dialog(
                transient_for=self,
                modal=True,
                message_type=Gtk.MessageType.ERROR,
                buttons=Gtk.ButtonsType.OK,
                text=f"Error exporting question stats: {e}",
            )
            error_dialog.connect("response", lambda d, r: d.destroy())
            error_dialog.present()

    def on_reset_data(self, button):
        if getattr(self, "engine", None) is None:
            self._show_engine_not_ready("Reset Data")
            return
        confirm_dialog = self._new_message_dialog(
            transient_for=self,
            modal=True,
            message_type=Gtk.MessageType.QUESTION,
            buttons=Gtk.ButtonsType.YES_NO,
            text="Are you sure you want to reset all data?"
        )
        confirm_dialog.connect("response", self.on_reset_confirm)
        confirm_dialog.present()

    def on_reset_confirm(self, dialog, response):
        dialog.destroy()
        if response == Gtk.ResponseType.YES:
            engine = getattr(self, "engine", None)
            if engine is None:
                self._show_engine_not_ready("Reset Data")
                return
            engine.reset_data()
            self._invalidate_readiness_and_recommendations_cache()
            self.update_dashboard()
            self.update_recommendations()
            self.update_daily_plan()
            self.update_streak_display()

    def on_view_health_log(self, button):
        log_path = os.path.join(Config.CONFIG_HOME, "migration.log")
        if not os.path.exists(log_path):
            self._show_text_dialog("Data Health Log", "No health log found yet.", Gtk.MessageType.INFO)
            return

        try:
            with open(log_path, "r", encoding="utf-8") as f:
                content = f.read().strip()
        except OSError as e:
            self._show_text_dialog("Data Health Log", f"Failed to read health log: {e}", Gtk.MessageType.ERROR)
            return

        self._show_scrolling_text("Data Health Log", content if content else "(log is empty)")

    def on_run_health_check(self, button):
        if getattr(self, "engine", None) is None:
            self._show_engine_not_ready("Data Health Check")
            return
        health = {}
        try:
            health = self.engine.run_data_health_check()
        except Exception as exc:
            self._show_text_dialog("Data Health Check", f"Failed to run health check: {exc}", Gtk.MessageType.ERROR)
            return

        notes = health.get("notes") if isinstance(health, dict) else None
        note_lines = ""
        if isinstance(notes, list) and notes:
            note_lines = "\nNotes:\n- " + "\n- ".join(str(n) for n in notes)

        health_text = (
            "Data health check complete.\n\n"
            f"Competence fixed: {health.get('competence_fixed', 0)}\n"
            f"SRS fixed: {health.get('srs_fixed', 0)}\n"
            f"Pomodoro fixed: {health.get('pomodoro_fixed', 0)}\n"
            f"Study days fixed: {health.get('study_days_fixed', 0)}\n"
            f"Exam date fixed: {health.get('exam_date_fixed', 0)}"
            f"{note_lines}"
        )
        self._show_text_dialog("Data Health Check", health_text, Gtk.MessageType.INFO)
        self.update_dashboard()

    def on_clear_syllabus_cache(self, _button):
        if getattr(self, "engine", None) is None:
            self._show_engine_not_ready("Clear Syllabus Cache")
            return
        try:
            before = self.engine.get_syllabus_import_cache_stats()
            result = self.engine.clear_syllabus_import_cache(clear_disk=True)
            after = self.engine.get_syllabus_import_cache_stats()
        except Exception as exc:
            self._show_text_dialog("Clear Syllabus Cache", f"Failed to clear cache: {exc}", Gtk.MessageType.ERROR)
            return

        lines = [
            "Syllabus cache cleared.",
            "",
            f"Memory parse entries: {int(before.get('memory_parse_entries', 0) or 0)} -> {int(after.get('memory_parse_entries', 0) or 0)}",
            f"Memory import entries: {int(before.get('memory_import_entries', 0) or 0)} -> {int(after.get('memory_import_entries', 0) or 0)}",
            "Hit rates reset: parse {0:.0%} -> {1:.0%} • import {2:.0%} -> {3:.0%}".format(
                float(before.get("parse_hit_rate", 0.0) or 0.0),
                float(after.get("parse_hit_rate", 0.0) or 0.0),
                float(before.get("import_hit_rate", 0.0) or 0.0),
                float(after.get("import_hit_rate", 0.0) or 0.0),
            ),
            f"Disk cache removed: {'yes' if bool(result.get('disk_removed')) else 'no'}",
        ]
        disk_error = result.get("disk_error")
        if isinstance(disk_error, str) and disk_error.strip():
            lines.append(f"Disk cache error: {disk_error}")
        self._show_text_dialog("Clear Syllabus Cache", "\n".join(lines), Gtk.MessageType.INFO)

    def on_view_syllabus_cache_stats(self, _button):
        if getattr(self, "engine", None) is None:
            self._show_engine_not_ready("Syllabus Cache Stats")
            return
        try:
            stats = self.engine.get_syllabus_import_cache_stats()
        except Exception as exc:
            self._show_text_dialog("Syllabus Cache Stats", f"Failed to read cache stats: {exc}", Gtk.MessageType.ERROR)
            return

        lines = [
            "Syllabus cache statistics",
            "",
            f"Memory parse entries: {int(stats.get('memory_parse_entries', 0) or 0)}",
            f"Memory import entries: {int(stats.get('memory_import_entries', 0) or 0)}",
            f"Parse hits/misses: {int(stats.get('parse_hits', 0) or 0)} / {int(stats.get('parse_misses', 0) or 0)} ({float(stats.get('parse_hit_rate', 0.0) or 0.0):.0%} hit)",
            f"Import hits/misses: {int(stats.get('import_hits', 0) or 0)} / {int(stats.get('import_misses', 0) or 0)} ({float(stats.get('import_hit_rate', 0.0) or 0.0):.0%} hit)",
            f"Disk cache exists: {'yes' if bool(stats.get('disk_exists')) else 'no'}",
            f"Disk entries: {int(stats.get('disk_entries', 0) or 0)}",
            f"Disk size: {int(stats.get('disk_bytes', 0) or 0)} bytes",
        ]
        updated = str(stats.get("disk_updated_at", "") or "").strip()
